// BUILD FOLLOW-UP 1 EMAIL - personalised by partner type
function getTemplate(type) {
  const t = (type || '').toLowerCase();
  if (t.includes('college') || t.includes('university')) return {
    subject: (fn) => 'Following up — campus partnership with [YOUR COMPANY], ' + fn,
    color: '#1D4ED8',
    body: (fn, d) => 'Just checking in on my last email about a campus partnership between <strong>' + (d.name || 'your institution') + '</strong> and <strong>[YOUR COMPANY]</strong>.<br><br>We\'d love to bring value to your students — through workshops, internships, or hackathons. Would a 15-minute call this week work?'
  };
  if (t.includes('influencer')) return {
    subject: (fn) => 'Hey ' + fn + ', still keen on the collab?',
    color: '#7C3AED',
    body: () => 'Just following up on the collab idea I sent over! I genuinely think your audience would love <strong>[YOUR PRODUCT]</strong> — and the deal is flexible to match your style.<br><br>Would love to hop on a quick call — totally casual, no pressure.'
  };
  if (t.includes('brand')) return {
    subject: (fn) => 'Quick follow-up — brand partnership with [YOUR COMPANY], ' + fn,
    color: '#059669',
    body: () => 'Following up on the brand partnership opportunity I shared earlier. We\'ve had great results with partners in your space.<br><br>Would a 15-minute call this week work?'
  };
  return {
    subject: (fn) => 'Quick follow-up — ' + fn + ', still interested in partnering?',
    color: '#374151',
    body: () => 'Just following up on my last email about partnering with <strong>[YOUR COMPANY]</strong>. Would a quick 15-minute call work?'
  };
}

const d = $input.first().json;
const firstName = (d.name || 'there').split(' ')[0];
const tpl = getTemplate(d.partner_type);

const emailBody = '<!DOCTYPE html><html><body style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;color:#333;line-height:1.6">'
  + '<p>Hi ' + firstName + ',</p>'
  + '<p>' + tpl.body(firstName, d) + '</p>'
  + '<p style="margin-top:20px"><a href="https://calendly.com/REPLACE_WITH_CALENDAR_LINK" style="background:' + tpl.color + ';color:#fff;padding:12px 24px;border-radius:6px;text-decoration:none;display:inline-block;font-weight:bold">Pick a Time</a></p>'
  + '<p style="margin-top:20px">If the timing is not right, just say the word — no hard feelings.<br><br>Best,<br><strong>[YOUR NAME]</strong><br>[YOUR COMPANY] · [YOUR EMAIL]</p>'
  + '<hr style="border:none;border-top:1px solid #eee;margin:28px 0">'
  + '<p style="font-size:11px;color:#999"><a href="mailto:[YOUR EMAIL]?subject=Unsubscribe" style="color:#999">Unsubscribe</a></p>'
  + '</body></html>';


// Threading headers for email client grouping
const inReplyTo = d.message_id ? '<' + d.message_id + '>' : '';
const references = d.thread_id ? '<' + d.thread_id + '>' : '';
const threadSubject = d.original_subject || tpl.subject(firstName);
return [{ json: { ...d, emailSubject: threadSubject, emailBody, inReplyTo, references } }];

